116	func parseCredentialOutput(output []byte) map[string]string {
117		values := map[string]string{}
118		for _, line := range strings.Split(string(output), "\n") {
119			line = strings.TrimSpace(line)
120			if line == "" {
121				continue
122			}
123			k, v, ok := strings.Cut(line, "=")
124			if ok {
125				values[k] = v
126			}
127		}
128		return values
129	}
