14	// TestBootstrap_ThroughputLineAndProgressTicker verifies end-to-end that
15	// running a real bootstrap with --stats and --progress populates per-side
16	// byte counters, prints a throughput line in the human output, and emits
17	// at least one render to the progress writer when progressOut is wired.
18	func TestBootstrap_ThroughputLineAndProgressTicker(t *testing.T) {
19		sourceRepo, sourceFS := newSourceRepo(t)
20		makeCommits(t, sourceRepo, sourceFS, 4)
21	
22		targetRepo, err := git.Init(memory.NewStorage())
23		if err != nil {
24			t.Fatalf("init target repo: %v", err)
25		}
26	
27		sourceServer := newSmartHTTPRepoServerV2(t, sourceRepo)
28		targetServer := newSmartHTTPRepoServer(t, targetRepo)
29		defer sourceServer.Close()
30		defer targetServer.Close()
31	
32		var progressBuf bytes.Buffer
33		cfg := Config{
34			Source:       Endpoint{URL: sourceServer.RepoURL()},
35			Target:       Endpoint{URL: targetServer.RepoURL()},
36			ProtocolMode: protocolModeAuto,
37			ShowStats:    true,
38			Progress:     true,
39			progressOut:  &progressBuf,
40		}
41	
42		result, err := Bootstrap(context.Background(), cfg)
43		if err != nil {
44			t.Fatalf("bootstrap failed: %v", err)
45		}
46		if result.Pushed != 1 {
47			t.Fatalf("expected one push, got %+v", result)
48		}
49	
50		// Per-side counters should record bytes on both sides.
51		sides := map[string]int64{}
52		for _, side := range result.Stats.Sides {
53			sides[side.Label] = side.Bytes
54		}
55		if sides["source"] <= 0 {
56			t.Errorf("expected non-zero source bytes, got %d", sides["source"])
57		}
58		if sides["target"] <= 0 {
59			t.Errorf("expected non-zero target bytes, got %d", sides["target"])
60		}
61		if result.Stats.ElapsedNanos <= 0 {
62			t.Errorf("expected non-zero elapsed nanos, got %d", result.Stats.ElapsedNanos)
63		}
64	
65		// Human-formatted output should include the new throughput line.
66		out := strings.Join(result.Lines(), "\n")
67		if !strings.Contains(out, "throughput: ") {
68			t.Errorf("missing throughput line in output:\n%s", out)
69		}
70		if !strings.Contains(out, "source=") || !strings.Contains(out, "target=") {
71			t.Errorf("throughput line should mention both sides:\n%s", out)
72		}
73	
74		// Progress writer should have received at least one frame. The bootstrap
75		// is very fast so we may only get the final terminate() render.
76		if progressBuf.Len() == 0 {
77			// Allow a brief grace window in case the goroutine had not flushed
78			// yet. terminate() inside finish() blocks on render so this should
79			// be unnecessary, but keep a small fallback for slow CI.
80			time.Sleep(50 * time.Millisecond)
81		}
82		if progressBuf.Len() == 0 {
83			t.Errorf("expected progress reporter to write at least one frame")
84		}
85		if !bytes.Contains(progressBuf.Bytes(), []byte("source:")) {
86			t.Errorf("progress output should mention source: %q", progressBuf.String())
87		}
88		if !bytes.Contains(progressBuf.Bytes(), []byte("target:")) {
89			t.Errorf("progress output should mention target: %q", progressBuf.String())
90		}
91	
92		// Print samples for human inspection when running with -v.
93		for _, line := range result.Lines() {
94			if strings.HasPrefix(line, "stats:") || strings.HasPrefix(line, "throughput:") {
95				t.Logf("output line: %s", line)
96			}
97		}
98		t.Logf("progress writer:\n%q", progressBuf.String())
99	}
